import type { StylexProps } from '../../../util';
import stylex from '@universe-design/stylex';
import clsx from 'clsx';
import React from 'react';
import { useCssScope } from '../../../config-provider/hooks';

import './index.less';
import { sxCascadeBox, sxListBox } from './sx';

export type ListBoxProps = React.ComponentPropsWithoutRef<'div'> & {
  cascaded?: boolean;
} & StylexProps;

export const ListBox = React.forwardRef<HTMLDivElement, ListBoxProps>(
  ({ className, cascaded = false, sx = [], ...restProps }, ref) => {
    const cssScope = useCssScope('list__box');
    return (
      <div
        ref={ref}
        className={clsx(
          cssScope(),
          stylex(stylex.compose(sxListBox, cascaded && sxCascadeBox, ...sx)),
          cascaded && cssScope('-cascaded'),
          className,
        )}
        {...restProps}
      />
    );
  },
);

export type ListScrollViewProps = React.ComponentPropsWithoutRef<'ul'>;

export const ListScrollView = React.forwardRef<HTMLUListElement, ListScrollViewProps>(
  ({ className, ...restProps }, ref) => {
    const cssScope = useCssScope('list__scrollView');

    return <ul ref={ref} className={clsx(cssScope(), className)} {...restProps} />;
  },
);
